def compute_score() -> tuple[str, float]:
    # Check for extraneous changes on first slide beyond the title
    first_slide_id = None
    # Find first slide id from original PPT
    from pptx import Presentation
    prs = Presentation(original_ppt_path)
    first_slide = prs.slides[0]
    if hasattr(first_slide, 'slide_id'): # python-pptx 0.6.21+
        first_slide_id = str(first_slide.slide_id)
    else:
        # fallback to slide_number
        first_slide_id = str(1)
    changed = False
    reasons = []
    # Check for modified animations
    for anim_tuple in ppt_diff.modified_animations:
        before, after = anim_tuple
        if before.slide_id == first_slide_id:
            changed = True
            reasons.append("Animations were changed on first slide.")
    # Check for modified transitions
    for trans_tuple in ppt_diff.modified_transitions:
        before, after = trans_tuple
        if before.slide_id == first_slide_id:
            changed = True
            reasons.append("Transitions were changed on first slide.")
    # Check for notes change
    for slide_tuple in ppt_diff.modified_slides:
        before, after = slide_tuple
        if before.slide_id == first_slide_id:
            # Check if notes changed
            if (before.notes or "") != (after.notes or ""):
                changed = True
                reasons.append("Slide notes were changed on first slide.")
    # Check for added/removed elements (element_count)
    for slide_tuple in ppt_diff.modified_slides:
        before, after = slide_tuple
        if before.slide_id == first_slide_id:
            if before.element_count != after.element_count:
                changed = True
                reasons.append("Elements were added/removed on first slide.")
    # Check for layout change
    for slide_tuple in ppt_diff.modified_slides:
        before, after = slide_tuple
        if before.slide_id == first_slide_id:
            if (before.layout_type or "") != (after.layout_type or ""):
                changed = True
                reasons.append("Layout type was changed on first slide.")
    # Check for changes to other text (besides title)
    # For this, compare all text shapes except the title
    import difflib
    original_prs = Presentation(original_ppt_path)
    modified_prs = Presentation(modified_ppt_path)
    orig_slide = original_prs.slides[0]
    mod_slide = modified_prs.slides[0]
    # Find title shape index in both
    def get_title_shape(slide):
        for shape in slide.shapes:
            if shape.has_text_frame and shape.text_frame.text.strip():
                return shape
        return None
    orig_title_shape = get_title_shape(orig_slide)
    mod_title_shape = get_title_shape(mod_slide)
    # Compare all other text shapes
    orig_texts = [shape.text_frame.text.strip() for shape in orig_slide.shapes if shape.has_text_frame and shape != orig_title_shape]
    mod_texts = [shape.text_frame.text.strip() for shape in mod_slide.shapes if shape.has_text_frame and shape != mod_title_shape]
    if orig_texts != mod_texts:
        changed = True
        reasons.append("Other text on first slide was changed.")
    if changed:
        return ("; ".join(reasons), 0.0)
    else:
        return ("No extraneous changes to first slide except title.", 1.0)

def compute_score() -> tuple[str, float]:
    # Only the first slide should be changed; all other slides untouched
    if ppt_diff.added_slides or ppt_diff.removed_slides:
        return ("Slides added or removed.", 0.0)
    # Animations or transitions
    if ppt_diff.added_animations or ppt_diff.removed_animations or ppt_diff.modified_animations:
        return ("Animations changed.", 0.0)
    if ppt_diff.added_transitions or ppt_diff.removed_transitions or ppt_diff.modified_transitions:
        return ("Transitions changed.", 0.0)

    changed = False
    reasons = []
    first_slide_ids = set()
    from pptx import Presentation
    orig_prs = Presentation(original_ppt_path)
    for i, slide in enumerate(orig_prs.slides):
        if hasattr(slide, 'slide_id'):
            first_slide_ids.add(str(slide.slide_id))
            if i == 0:
                first_slide_id = str(slide.slide_id)
        else:
            first_slide_ids.add(str(i+1))
            if i == 0:
                first_slide_id = str(i+1)
    # Check for modified slides not the first
    for slide_tuple in ppt_diff.modified_slides:
        before, after = slide_tuple
        if before.slide_id != first_slide_id:
            changed = True
            reasons.append(f"Slide {before.slide_number} was modified.")
    # Check for added/removed slides
    for slide in ppt_diff.added_slides:
        if slide.slide_id != first_slide_id:
            changed = True
            reasons.append(f"Slide {slide.slide_number} was added.")
    for slide in ppt_diff.removed_slides:
        if slide.slide_id != first_slide_id:
            changed = True
            reasons.append(f"Slide {slide.slide_number} was removed.")
    # Check for modified animations/transitions on other slides
    for anim_tuple in ppt_diff.modified_animations:
        before, after = anim_tuple
        if before.slide_id != first_slide_id:
            changed = True
            reasons.append(f"Animations were changed on slide {before.slide_number}.")
    for trans_tuple in ppt_diff.modified_transitions:
        before, after = trans_tuple
        if before.slide_id != first_slide_id:
            changed = True
            reasons.append(f"Transitions were changed on slide {before.slide_number}.")
    if changed:
        return ("; ".join(reasons), 0.0)
    else:
        return ("No extraneous changes to other slides.", 1.0)
